import React, { useEffect, useRef, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import DailyIframe from '@daily-co/daily-js';
import toast from 'react-hot-toast';
import appointmentService from '../../services/appointmentService';
import { useAuth } from '../../context/AuthContext';

/**
 * VideoCallPage
 * Route: /appointments/:id/video-call
 *
 * Flow:
 * 1. POST /appointments/:id/join-meeting/ → मिळतं { meeting_link, token }
 * 2. Daily.co iframe त्याच page वर embed होतो (redirect नाही)
 * 3. Call end झाल्यावर /appointments/:id वर navigate
 */
function VideoCallPage() {
  const { id }   = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const callContainerRef = useRef(null);
  const callFrameRef     = useRef(null);

  const [status, setStatus]   = useState('loading'); // loading | joining | in-call | ended | error
  const [errorMsg, setErrorMsg] = useState('');
  const [apptInfo, setApptInfo] = useState(null);

  useEffect(() => {
    // React Strict Mode मध्ये useEffect दोनदा run होतो.
    // जर frame आधीच exist करत असेल तर नवीन बनवू नका.
    if (callFrameRef.current) return;

    let frame = null;

    const initCall = async () => {
      try {
        // 1. Join meeting — backend marks meeting_joined_at + returns token
        const data = await appointmentService.joinMeeting(id);

        if (!data.success) {
          setErrorMsg(data.message || 'Meeting link मिळाली नाही.');
          setStatus('error');
          return;
        }

        const { meeting_link, token } = data;
        setApptInfo(data);
        setStatus('joining');

        // 2. आधीचा frame असेल तर destroy करा (safety check)
        if (DailyIframe.getCallInstance()) {
          DailyIframe.getCallInstance().destroy();
        }

        // 3. Create Daily iframe — same page embed
        frame = DailyIframe.createFrame(callContainerRef.current, {
          iframeStyle: {
            width: '100%',
            height: '100%',
            border: 'none',
            borderRadius: '12px',
          },
          showLeaveButton: true,
          showFullscreenButton: true,
          showLocalVideo: true,
          showParticipantsBar: true,
          allowMultipleCallInstances: false,
        });

        callFrameRef.current = frame;

        // 3. Event listeners
        frame.on('joining-meeting', () => setStatus('joining'));
        frame.on('joined-meeting',  () => {
          setStatus('in-call');
          toast.success('Meeting मध्ये join झालात! 🎥');
        });
        frame.on('left-meeting', () => {
          setStatus('ended');
          toast('Meeting संपली.', { icon: '👋' });
          setTimeout(() => navigate(`/appointments/${id}`), 2000);
        });
        frame.on('error', (e) => {
          setErrorMsg(e?.errorMsg || 'Meeting error आला.');
          setStatus('error');
        });

        // 4. Join with token (private room)
        await frame.join({
          url: meeting_link,
          token: token || undefined, // token नसेल तर undefined (public room fallback)
          userName: user?.full_name || user?.email || 'User',
        });

      } catch (err) {
        const msg = err?.response?.data?.message || err.message || 'Meeting join करता आली नाही.';
        setErrorMsg(msg);
        setStatus('error');
        toast.error(msg);
      }
    };

    initCall();

    // Cleanup — frame destroy on unmount
    return () => {
      if (callFrameRef.current) {
        callFrameRef.current.destroy();
        callFrameRef.current = null;
      }
    };
  }, [id, navigate, user]);

  // ── Loading State ────────────────────────────────────────────────────────
  if (status === 'loading' || status === 'joining') {
    return (
      <div className="min-h-screen bg-gray-900 flex flex-col items-center justify-center gap-4">
        <div className="w-16 h-16 bg-blue-600 rounded-full flex items-center justify-center animate-pulse">
          <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2}
              d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
          </svg>
        </div>
        <p className="text-white text-lg font-medium">
          {status === 'loading' ? 'Meeting तयार होतेय...' : 'Joining meeting...'}
        </p>
        <p className="text-gray-400 text-sm">कृपया थांबा</p>
      </div>
    );
  }

  // ── Error State ──────────────────────────────────────────────────────────
  if (status === 'error') {
    return (
      <div className="min-h-screen bg-gray-900 flex flex-col items-center justify-center gap-4 px-4">
        <div className="w-16 h-16 bg-red-600 rounded-full flex items-center justify-center">
          <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </div>
        <p className="text-white text-lg font-medium text-center">Meeting join होऊ शकली नाही</p>
        <p className="text-red-400 text-sm text-center max-w-sm">{errorMsg}</p>
        <button
          onClick={() => navigate(`/appointments/${id}`)}
          className="mt-4 px-6 py-2.5 bg-white text-gray-900 rounded-xl text-sm font-medium hover:bg-gray-100"
        >
          ← Appointment वर परत जा
        </button>
      </div>
    );
  }

  // ── Call Ended ───────────────────────────────────────────────────────────
  if (status === 'ended') {
    return (
      <div className="min-h-screen bg-gray-900 flex flex-col items-center justify-center gap-4">
        <div className="w-16 h-16 bg-green-600 rounded-full flex items-center justify-center">
          <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <p className="text-white text-lg font-medium">Meeting संपली 👋</p>
        <p className="text-gray-400 text-sm">Appointment page वर redirect होतोय...</p>
      </div>
    );
  }

  // ── In-Call State — Daily iframe renders here ────────────────────────────
  return (
    <div className="h-screen bg-gray-900 flex flex-col">

      {/* Top Bar */}
      <div className="flex items-center justify-between px-4 py-2 bg-gray-800 flex-shrink-0">
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse" />
          <span className="text-white text-sm font-medium">Live Consultation</span>
        </div>
        <button
          onClick={() => navigate(`/appointments/${id}`)}
          className="text-xs text-gray-400 hover:text-white transition-colors flex items-center gap-1"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
          Back
        </button>
      </div>

      {/* Daily.co iframe container — full remaining height */}
      <div
        ref={callContainerRef}
        className="flex-1 w-full"
        style={{ minHeight: 0 }}
      />
    </div>
  );
}

export default VideoCallPage;
